// ConfigureInterfaceConfigureInterfaceConfigInterfaceResult includes the requested fields of the GraphQL type ConfigInterfaceResult.
type ConfigureInterfaceConfigureInterfaceConfigInterfaceResult struct {
	// True if SFW content mode is enabled
	SfwContentMode bool `json:"sfwContentMode"`
	// Ordered list of items that should be shown in the menu
	MenuItems []string `json:"menuItems"`
	// Enable sound on mouseover previews
	SoundOnPreview *bool `json:"soundOnPreview"`
	// Show title and tags in wall view
	WallShowTitle *bool `json:"wallShowTitle"`
	// Wall playback type
	WallPlayback *string `json:"wallPlayback"`
	// Show scene scrubber by default
	ShowScrubber *bool `json:"showScrubber"`
	// Maximum duration (in seconds) in which a scene video will loop in the scene player
	MaximumLoopDuration *int `json:"maximumLoopDuration"`
	// True if we should not auto-open a browser window on startup
	NoBrowser *bool `json:"noBrowser"`
	// True if we should send desktop notifications
	NotificationsEnabled *bool `json:"notificationsEnabled"`
	// If true, video will autostart on load in the scene player
	AutostartVideo *bool `json:"autostartVideo"`
	// If true, video will autostart when loading from play random or play selected
	AutostartVideoOnPlaySelected *bool `json:"autostartVideoOnPlaySelected"`
	// If true, next scene in playlist will be played at video end by default
	ContinuePlaylistDefault *bool `json:"continuePlaylistDefault"`
	// If true, studio overlays will be shown as text instead of logo images
	ShowStudioAsText *bool `json:"showStudioAsText"`
	// Custom CSS
	Css        *string `json:"css"`
	CssEnabled *bool   `json:"cssEnabled"`
	// Custom Javascript
	Javascript        *string `json:"javascript"`
	JavascriptEnabled *bool   `json:"javascriptEnabled"`
	// Custom Locales
	CustomLocales        *string `json:"customLocales"`
	CustomLocalesEnabled *bool   `json:"customLocalesEnabled"`
	// When true, disables all customizations (plugins, CSS, JavaScript, locales) for troubleshooting
	DisableCustomizations *bool `json:"disableCustomizations"`
	// Interface language
	Language      *string                          `json:"language"`
	ImageLightbox *ConfigImageLightboxResultFields `json:"imageLightbox"`
	// Fields are true if creating via dropdown menus are disabled
	DisableDropdownCreate *ConfigDisableDropdownCreateFields `json:"disableDropdownCreate"`
	// Handy Connection Key
	HandyKey *string `json:"handyKey"`
	// Funscript Time Offset
	FunscriptOffset *int `json:"funscriptOffset"`
	// Whether to use Stash Hosted Funscript
	UseStashHostedFunscript *bool `json:"useStashHostedFunscript"`
}

